{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires solving a self-consistent mean-field equation for occupancy. I will decompose this into deriving the transcendental equation and then solving it numerically.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Derive the self-consistent mean-field equation for the occupancy <n> of a lattice gas. Use the grand canonical ensemble framework where the energy of a particle is related to the interaction energy with neighbors. Given the parameters: epsilon = - (k_B * T) / (2 * pi), chemical potential mu = 0.1 * k_B * T, and coordination numbers z_h = 4 and z_v = 8. Note that the total coordination number z is the sum of z_h and z_v. The equation should relate <n> to the Boltzmann factor involving mu and the interaction energy term z * epsilon * <n>. State the final simplified transcendental equation for <n> in terms of the exponential function."
    },
    {
      "label": "helper_2",
      "instructions": "Perform a high-precision numerical solution for the occupancy <n> using the equation derived by helper_1. Use the following constants: T = 300 K, mu = 0.1 * k_B * T, epsilon = - (k_B * T) / (2 * pi), and z = 12 (from z_h = 4 and z_v = 8). Since k_B and T appear in both the numerator and denominator of the exponent, they should cancel out, leaving the equation in terms of dimensionless ratios. Provide the final numerical value of <n> rounded to four decimal places."
    }
  ],
  "synthesis_brief": "Combine the derived equation from helper_1 and the numerical solution from helper_2. Verify the final result by substituting the value of <n> back into the transcendental equation to ensure both sides are equal. Return the final answer in the format FINAL_ANSWER: <value> and JUSTIFICATION: <brief explanation>."
}

